// Parse all data sources
const company = $('Loop Companies').item.json.name;
const url = $('Loop Companies').item.json.url;
const previousData = $('Read Previous Data').all();

// Parse website
const websiteHtml = $('Fetch Website').item.json.body || '';
const titleMatch = websiteHtml.match(/<title[^>]*>([^<]+)<\/title>/i);
const descMatch = websiteHtml.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i);
const h1Matches = websiteHtml.match(/<h1[^>]*>([^<]+)<\/h1>/gi) || [];

const website = {
  title: titleMatch ? titleMatch[1].trim() : null,
  description: descMatch ? descMatch[1].trim() : null,
  h1Tags: h1Matches.map(h => h.replace(/<[^>]+>/g, '').trim()),
  hasNews: websiteHtml.toLowerCase().includes('news'),
  hasBlog: websiteHtml.toLowerCase().includes('blog'),
  hasPricing: websiteHtml.toLowerCase().includes('pricing'),
  hasFeatures: websiteHtml.toLowerCase().includes('features')
};

// Parse blog
const blogHtml = $('Fetch Blog').item.json.body || '';
const blogArticles = blogHtml.match(/<article[^>]*>([\s\S]*?)<\/article>/gi) || [];
const blog = {
  articlesFound: blogArticles.length,
  recentArticles: blogArticles.slice(0, 5).map((article, i) => {
    const titleMatch = article.match(/<h[1-3][^>]*>([^<]+)<\/h[1-3]>/i);
    const dateMatch = article.match(/<time[^>]*datetime=["']([^"']+)["']/i) || article.match(/(\d{4}-\d{2}-\d{2})/);
    return {
      title: titleMatch ? titleMatch[1].trim() : `Article ${i+1}`,
      date: dateMatch ? dateMatch[1] : null,
      preview: article.replace(/<[^>]+>/g, '').substring(0, 200).trim()
    };
  })
};

// Parse reviews/testimonials
const reviewsHtml = $('Fetch Reviews').item.json.body || '';
const reviewMatches = reviewsHtml.match(/<div[^>]*class="[^"]*review[^"]*"[^>]*>([\s\S]*?)<\/div>/gi) || [];
const reviews = {
  found: reviewMatches.length > 0,
  count: reviewMatches.length,
  samples: reviewMatches.slice(0, 3).map(r => r.replace(/<[^>]+>/g, '').substring(0, 150).trim())
};

// Extract previous data
const previous = previousData.length > 0 ? {
  date: previousData[0].json.Date || null,
  summary: previousData[0].json['AI Summary'] || null
} : null;

return {
  company: company,
  url: url,
  currentData: {
    website: website,
    blog: blog,
    reviews: reviews,
    scrapedAt: new Date().toISOString()
  },
  previousData: previous
};

// Parse AI JSON response and handle errors
const response = $input.item.json;
let aiData;

try {
  // Extract content from OpenAI response
  const content = response.choices?.[0]?.message?.content || '';

  // Parse JSON
  aiData = JSON.parse(content);

  // Validate required fields
  const required = ['newFeatures', 'problems', 'reviewInsights', 'news',
                   'blogArticles', 'customerPains', 'customerWants', 'summary'];

  for (const field of required) {
    if (!(field in aiData)) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

} catch (error) {
  // Fallback structure on error
  console.error('AI JSON parsing error:', error.message);
  aiData = {
    newFeatures: [],
    problems: [`Помилка парсингу AI: ${error.message}`],
    reviewInsights: 'Дані недоступні',
    news: [],
    blogArticles: [],
    customerPains: [],
    customerWants: [],
    summary: 'Аналіз не вдався - потрібна ручна перевірка'
  };
}

// Pass through original data + parsed AI
return {
  company: $('Loop Companies').item.json.name,
  url: $('Loop Companies').item.json.url,
  aiAnalysis: aiData,
  parsedAt: new Date().toISOString()
};

const data = $input.item.json;
const ai = data.aiAnalysis || {};

// Helper: convert array to comma-separated string
const arrayToString = (arr) => {
  if (!Array.isArray(arr)) return '-';
  if (arr.length === 0) return '-';
  return arr.join(', ');
};

// Helper: convert blog articles to readable string
const blogToString = (articles) => {
  if (!Array.isArray(articles)) return '-';
  if (articles.length === 0) return '-';
  return articles.map(a =>
    `${a.title} (${a.date || 'дата невідома'}): ${a.summary.substring(0, 100)}...`
  ).join(' | ');
};

// Create 16-column row
return {
  // Column 1: Дата
  'Дата': new Date().toISOString().split('T')[0],

  // Column 2: Компанія
  'Компанія': data.company,

  // Column 3: URL
  'URL': data.url,

  // Column 4: Нові фічі
  'Нові фічі': arrayToString(ai.newFeatures),

  // Column 5: Проблеми
  'Проблеми': arrayToString(ai.problems),

  // Column 6: Інсайти з коментарів
  'Інсайти з коментарів': ai.reviewInsights || '-',

  // Column 7: Новини (з останньої перевірки)
  'Новини (з останньої перевірки)': arrayToString(ai.news),

  // Column 8: Статті в блозі (з останньої перевірки)
  'Статті в блозі (з останньої перевірки)': blogToString(ai.blogArticles),

  // Column 9: YouTube активність
  'YouTube активність': data.youtubeActivity || '-',

  // Column 10: Facebook активність
  'Facebook активність': data.facebookActivity || '-',

  // Column 11: LinkedIn активність
  'LinkedIn активність': data.linkedinActivity || '-',

  // Column 12: Згадки на агрегаторах (поки пусто)
  'Згадки на агрегаторах': '-',

  // Column 13: Кількість згадок в соцмережах (поки пусто)
  'Кількість згадок в соцмережах': '0',

  // Column 14: Болі клієнтів з коментарів
  'Болі клієнтів з коментарів': arrayToString(ai.customerPains),

  // Column 15: Хотілки клієнтів з коментарів
  'Хотілки клієнтів з коментарів': arrayToString(ai.customerWants),

  // Column 16: AI Summary
  'AI Summary': ai.summary || '-'
};

// Aggregate all companies results
const allResults = $input.all();

// Build Telegram message
let message = `📊 *Щоденний звіт моніторингу конкурентів*\n`;
message += `📅 Дата: ${new Date().toLocaleDateString('uk-UA')}\n\n`;

allResults.forEach((item, index) => {
  const summary = item.json['AI Summary'] || '';
  const company = item.json.Company;

  // Extract key info from AI summary (first 150 chars)
  const shortSummary = summary.substring(0, 150).trim() + (summary.length > 150 ? '...' : '');

  message += `${index + 1}. *${company}*\n${shortSummary}\n\n`;
});

message += `\n📋 *Детальний звіт:*\n[Відкрити Google Sheets](YOUR_GOOGLE_SHEET_URL)`;

return { message };

// Auto-detect YouTube channel from website HTML
const websiteHtml = $('Fetch Website').item.json.body || '';
const companyName = $('Loop Companies').item.json.name;

// Method 1: Extract from YouTube links in HTML
const youtubePatterns = [
  /youtube\.com\/channel\/([a-zA-Z0-9_-]+)/i,
  /youtube\.com\/c\/([a-zA-Z0-9_-]+)/i,
  /youtube\.com\/user\/([a-zA-Z0-9_-]+)/i,
  /youtube\.com\/@([a-zA-Z0-9_-]+)/i
];

let channelId = null;
let channelUrl = null;

for (const pattern of youtubePatterns) {
  const match = websiteHtml.match(pattern);
  if (match) {
    channelUrl = match[0];
    channelId = match[1];
    break;
  }
}

return {
  company: companyName,
  youtubeChannelId: channelId,
  youtubeUrl: channelUrl,
  autoDetected: !!channelId
};

const response = $input.item.json;
const company = $('Loop Companies').item.json.name;

// Check if YouTube API returned data
if (!response.items || response.items.length === 0) {
  return {
    company: company,
    youtubeActivity: 'Немає нових відео за тиждень'
  };
}

const videos = response.items;
const videoCount = videos.length;
const latestVideo = videos[0];

// Format activity string
const activity = `${videoCount} нових відео за тиждень. ` +
                 `Останнє: "${latestVideo.snippet.title}" (${latestVideo.snippet.publishedAt.split('T')[0]})`;

return {
  company: company,
  youtubeActivity: activity,
  youtubeVideos: videos.slice(0, 3).map(v => ({
    title: v.snippet.title,
    publishedAt: v.snippet.publishedAt,
    url: `https://www.youtube.com/watch?v=${v.id.videoId}`
  }))
};

const websiteHtml = $('Fetch Website').item.json.body || '';
const company = $('Loop Companies').item.json.name;

// Extract social media links
const extractUrl = (pattern) => {
  const match = websiteHtml.match(pattern);
  return match ? match[0] : null;
};

const social = {
  company: company,
  linkedin: extractUrl(/linkedin\.com\/company\/[a-zA-Z0-9_-]+/i),
  facebook: extractUrl(/facebook\.com\/[a-zA-Z0-9._-]+/i),
  twitter: extractUrl(/twitter\.com\/[a-zA-Z0-9_]+/i),
  instagram: extractUrl(/instagram\.com\/[a-zA-Z0-9._]+/i)
};

return social;

const data = $input.item.json;

const activities = [];

if (data.linkedin) {
  activities.push(`LinkedIn: ${data.linkedin}`);
}
if (data.facebook) {
  activities.push(`Facebook: ${data.facebook}`);
}
if (data.twitter) {
  activities.push(`Twitter: ${data.twitter}`);
}

const linkedinActivity = data.linkedin ? 'Сторінка знайдена' : '-';
const facebookActivity = data.facebook ? 'Сторінка знайдена' : '-';

return {
  company: data.company,
  linkedinActivity: linkedinActivity,
  facebookActivity: facebookActivity,
  allSocialLinks: activities.join('; ') || '-'
};
